import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { FiShield, FiArrowLeft, FiCalendar, FiClock, FiMapPin, FiCheck, FiPlus, FiMinus } from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import { Service } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS, API_BASE_URL } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';

interface ServiceType {
  service_type_id: string;
  service_type_name: string;
  price: number;
  description?: string;
}

interface CartItem {
  service_type_id: string;
  service_type_name: string;
  price: number;
  quantity: number;
}

const ServiceDetails: React.FC = () => {
  const { serviceName } = useParams<{ serviceName: string }>();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState<'types' | 'details' | 'confirmation'>('types');
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedTime, setSelectedTime] = useState('');
  const [address, setAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [isBooking, setIsBooking] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [serviceTypes, setServiceTypes] = useState<ServiceType[]>([]);

  // Fetch service details
  const { data: serviceData, isLoading } = useQuery(
    ['service', serviceName],
    () => apiService.get<Service[]>(API_ENDPOINTS.FETCH_SERVICES),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load service details');
      }
    }
  );

  const service = serviceData?.data?.find(s => s.service_name === decodeURIComponent(serviceName || ''));

  // Fetch service types
  const { data: serviceTypesData, isLoading: typesLoading } = useQuery(
    ['serviceTypes', serviceName],
    () => apiService.get<{ service_types: ServiceType[] }>(`${API_ENDPOINTS.GET_SERVICE_TYPES}?service_name=${encodeURIComponent(serviceName || '')}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load service types');
      }
    }
  );

  useEffect(() => {
    if (serviceTypesData?.data?.service_types) {
      setServiceTypes(serviceTypesData.data.service_types);
    }
  }, [serviceTypesData]);

  // Available time slots
  const timeSlots = [
    '9:00 AM - 11:00 AM',
    '11:00 AM - 1:00 PM', 
    '2:00 PM - 4:00 PM',
    '4:00 PM - 6:00 PM',
    '6:00 PM - 8:00 PM'
  ];

  // Get minimum date (today)
  const today = new Date().toISOString().split('T')[0];

  const addToCart = (serviceType: ServiceType) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.service_type_id === serviceType.service_type_id);
      if (existing) {
        return prev.map(item => 
          item.service_type_id === serviceType.service_type_id 
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      } else {
        return [...prev, { ...serviceType, quantity: 1 }];
      }
    });
  };

  const removeFromCart = (serviceTypeId: string) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.service_type_id === serviceTypeId);
      if (existing && existing.quantity > 1) {
        return prev.map(item => 
          item.service_type_id === serviceTypeId 
            ? { ...item, quantity: item.quantity - 1 }
            : item
        );
      } else {
        return prev.filter(item => item.service_type_id !== serviceTypeId);
      }
    });
  };

  const getCartItemQuantity = (serviceTypeId: string) => {
    const item = cartItems.find(item => item.service_type_id === serviceTypeId);
    return item ? item.quantity : 0;
  };

  const calculateSubtotal = () => {
    return cartItems.reduce((total, item) => total + (item.price * item.quantity), 0);
  };

  const calculateDiscount = () => {
    return calculateSubtotal() * 0.15; // 15% discount
  };

  const calculateTotal = () => {
    return calculateSubtotal() - calculateDiscount();
  };

  const handleProceedToDetails = () => {
    if (cartItems.length === 0) {
      toast.error('Please select at least one service type');
      return;
    }
    setCurrentStep('details');
  };

  const handleProceedToConfirmation = () => {
    if (!selectedDate || !selectedTime || !address.trim()) {
      toast.error('Please fill in all required fields');
      return;
    }
    setCurrentStep('confirmation');
  };

  const handleBooking = async () => {
    setIsBooking(true);
    try {
      const response = await apiService.post(API_ENDPOINTS.CREATE_BOOKING, {
        action: 'create_booking',
        service_name: service?.service_name,
        service_date: selectedDate,
        time_slot: selectedTime,
        service_address: address,
        special_notes: notes,
        subtotal: calculateSubtotal(),
        discount_amount: calculateDiscount(),
        total_amount: calculateTotal(),
        payment_method: 'cash',
        cart_items: cartItems
      });

      if (response.data?.status === 'success') {
        toast.success('Booking created successfully!');
        navigate('/bookings');
      } else {
        toast.error(response.data?.message || 'Booking failed');
      }
    } catch (error) {
      toast.error('Failed to create booking');
    } finally {
      setIsBooking(false);
    }
  };

  if (isLoading || typesLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
      </div>
    );
  }

  if (!service) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">Service Not Found</h2>
          <p className="text-gray-600 mb-4">The requested service could not be found.</p>
          <button
            onClick={() => navigate('/dashboard')}
            className="btn btn-primary"
          >
            Back to Dashboard
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center h-16">
            <button
              onClick={() => navigate('/dashboard')}
              className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
            >
              <FiArrowLeft className="w-5 h-5" />
            </button>
            <div className="ml-4">
              <h1 className="text-xl font-semibold text-gray-900">Complete Booking</h1>
              <p className="text-sm text-gray-500">{service.service_name}</p>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Progress Steps */}
        <div className="mb-8">
          <div className="flex items-center justify-center space-x-4">
            <div className={`flex items-center ${currentStep === 'types' ? 'text-teal-600' : 'text-gray-400'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${currentStep === 'types' ? 'border-teal-600 bg-teal-600 text-white' : 'border-gray-300'}`}>
                1
              </div>
              <span className="ml-2 text-sm font-medium">Choose Services</span>
            </div>
            <div className={`w-16 h-0.5 ${currentStep === 'details' || currentStep === 'confirmation' ? 'bg-teal-600' : 'bg-gray-300'}`}></div>
            <div className={`flex items-center ${currentStep === 'details' ? 'text-teal-600' : currentStep === 'confirmation' ? 'text-teal-600' : 'text-gray-400'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${currentStep === 'details' || currentStep === 'confirmation' ? 'border-teal-600 bg-teal-600 text-white' : 'border-gray-300'}`}>
                2
              </div>
              <span className="ml-2 text-sm font-medium">Details</span>
            </div>
            <div className={`w-16 h-0.5 ${currentStep === 'confirmation' ? 'bg-teal-600' : 'bg-gray-300'}`}></div>
            <div className={`flex items-center ${currentStep === 'confirmation' ? 'text-teal-600' : 'text-gray-400'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${currentStep === 'confirmation' ? 'border-teal-600 bg-teal-600 text-white' : 'border-gray-300'}`}>
                3
              </div>
              <span className="ml-2 text-sm font-medium">Confirm</span>
            </div>
          </div>
        </div>

        {/* Step 1: Choose Service Types */}
        {currentStep === 'types' && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-6"
          >
            <div className="bg-white rounded-lg shadow-sm p-6">
              <h2 className="text-xl font-bold text-gray-900 mb-6">Choose Your Services</h2>
              
              {serviceTypes.length === 0 ? (
                <div className="text-center py-8">
                  <FiShield className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                  <p className="text-gray-500">No service types available for this service.</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {serviceTypes.map((serviceType) => (
                    <div key={serviceType.service_type_id} className="border border-gray-200 rounded-lg p-4">
                      <div className="flex items-center justify-between">
                        <div className="flex-1">
                          <h3 className="font-semibold text-gray-900">{serviceType.service_type_name}</h3>
                          {serviceType.description && (
                            <p className="text-sm text-gray-600 mt-1">{serviceType.description}</p>
                          )}
                          <p className="text-lg font-bold text-teal-600 mt-2">₹{serviceType.price}</p>
                        </div>
                        <div className="flex items-center space-x-3">
                          {getCartItemQuantity(serviceType.service_type_id) > 0 && (
                            <>
                              <button
                                onClick={() => removeFromCart(serviceType.service_type_id)}
                                className="w-8 h-8 rounded-full bg-red-100 text-red-600 flex items-center justify-center hover:bg-red-200 transition-colors"
                              >
                                <FiMinus className="w-4 h-4" />
                              </button>
                              <span className="text-lg font-semibold text-gray-900 w-8 text-center">
                                {getCartItemQuantity(serviceType.service_type_id)}
                              </span>
                            </>
                          )}
                          <button
                            onClick={() => addToCart(serviceType)}
                            className="w-8 h-8 rounded-full bg-teal-100 text-teal-600 flex items-center justify-center hover:bg-teal-200 transition-colors"
                          >
                            <FiPlus className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Cart Summary */}
            {cartItems.length > 0 && (
              <div className="bg-white rounded-lg shadow-sm p-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Selected Services</h3>
                <div className="space-y-2">
                  {cartItems.map((item) => (
                    <div key={item.service_type_id} className="flex justify-between items-center">
                      <span className="text-gray-700">{item.service_type_name} x {item.quantity}</span>
                      <span className="font-semibold">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                  <div className="border-t pt-2 mt-4">
                    <div className="flex justify-between items-center font-semibold text-lg">
                      <span>Total:</span>
                      <span className="text-teal-600">₹{calculateSubtotal()}</span>
                    </div>
                  </div>
                </div>
              </div>
            )}

            <div className="flex justify-end">
              <button
                onClick={handleProceedToDetails}
                disabled={cartItems.length === 0}
                className="px-6 py-3 bg-teal-600 text-white rounded-lg font-medium hover:bg-teal-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
              >
                Proceed to Details
              </button>
            </div>
          </motion.div>
        )}

        {/* Step 2: Booking Details */}
        {currentStep === 'details' && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-6"
          >
            <div className="bg-white rounded-lg shadow-sm p-6">
              <h2 className="text-xl font-bold text-gray-900 mb-6">Booking Details</h2>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Date Selection */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    <FiCalendar className="inline w-4 h-4 mr-1" />
                    Select Date
                  </label>
                  <input
                    type="date"
                    min={today}
                    value={selectedDate}
                    onChange={(e) => setSelectedDate(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500"
                  />
                </div>

                {/* Time Selection */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    <FiClock className="inline w-4 h-4 mr-1" />
                    Select Time
                  </label>
                  <select
                    value={selectedTime}
                    onChange={(e) => setSelectedTime(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500"
                  >
                    <option value="">Choose a time slot</option>
                    {timeSlots.map((time) => (
                      <option key={time} value={time}>{time}</option>
                    ))}
                  </select>
                </div>
              </div>

              {/* Address */}
              <div className="mt-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  <FiMapPin className="inline w-4 h-4 mr-1" />
                  Service Address
                </label>
                <textarea
                  value={address}
                  onChange={(e) => setAddress(e.target.value)}
                  placeholder="Enter your complete address"
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500"
                />
              </div>

              {/* Special Notes */}
              <div className="mt-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Special Notes (Optional)
                </label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Any special instructions or requirements"
                  rows={2}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500"
                />
              </div>
            </div>

            <div className="flex justify-between">
              <button
                onClick={() => setCurrentStep('types')}
                className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg font-medium hover:bg-gray-50 transition-colors"
              >
                Back
              </button>
              <button
                onClick={handleProceedToConfirmation}
                className="px-6 py-3 bg-teal-600 text-white rounded-lg font-medium hover:bg-teal-700 transition-colors"
              >
                Review & Confirm
              </button>
            </div>
          </motion.div>
        )}

        {/* Step 3: Confirmation */}
        {currentStep === 'confirmation' && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-6"
          >
            <div className="bg-white rounded-lg shadow-sm p-6">
              <h2 className="text-xl font-bold text-gray-900 mb-6">Booking Summary</h2>
              
              <div className="space-y-4">
                <div className="border-b pb-4">
                  <h3 className="font-semibold text-gray-900 mb-2">Selected Services</h3>
                  {cartItems.map((item) => (
                    <div key={item.service_type_id} className="flex justify-between items-center py-1">
                      <span className="text-gray-700">{item.service_type_name} x {item.quantity}</span>
                      <span className="font-semibold">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                </div>

                <div className="border-b pb-4">
                  <h3 className="font-semibold text-gray-900 mb-2">Booking Details</h3>
                  <div className="space-y-2 text-sm">
                    <div className="flex justify-between">
                      <span className="text-gray-600">Date:</span>
                      <span className="text-gray-900">{selectedDate}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-600">Time:</span>
                      <span className="text-gray-900">{selectedTime}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-600">Address:</span>
                      <span className="text-gray-900">{address}</span>
                    </div>
                    {notes && (
                      <div className="flex justify-between">
                        <span className="text-gray-600">Notes:</span>
                        <span className="text-gray-900">{notes}</span>
                      </div>
                    )}
                  </div>
                </div>

                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span className="text-gray-600">Subtotal:</span>
                    <span className="font-semibold">₹{calculateSubtotal()}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Discount (15%):</span>
                    <span className="font-semibold text-green-600">-₹{calculateDiscount()}</span>
                  </div>
                  <div className="flex justify-between text-lg font-bold text-teal-600 border-t pt-2">
                    <span>Total Amount:</span>
                    <span>₹{calculateTotal()}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex justify-between">
              <button
                onClick={() => setCurrentStep('details')}
                className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg font-medium hover:bg-gray-50 transition-colors"
              >
                Back
              </button>
              <button
                onClick={handleBooking}
                disabled={isBooking}
                className="px-6 py-3 bg-teal-600 text-white rounded-lg font-medium hover:bg-teal-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
              >
                {isBooking ? (
                  <div className="flex items-center">
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                    Creating Booking...
                  </div>
                ) : (
                  `Confirm Booking - ₹${calculateTotal()}`
                )}
              </button>
            </div>
          </motion.div>
        )}
      </div>
    </div>
  );
};

export default ServiceDetails;
